import React, { useState, useEffect } from 'react';
import NavbarHome from '../components/NavbarHome';
import HeroHome from '../components/HeroHome';
import MarqueeBanner from '../components/MarqueeBanner';
import LearnSection from '../components/LearnSection';
import CulturalContentSection from '../components/CulturalContentSection';
import MultimodalSection from '../components/MultimodalSection';
import FooterHome from '../components/FooterHome';
import apiConfig from '../services/apiConfig';

const Home = () => {
    const [wordOfDay, setWordOfDay] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        apiConfig.get('/api/dictionary/words/daily')
            .then(data => {
                setWordOfDay(data);
                setLoading(false);
            })
            .catch(err => {
                console.warn("Usando datos locales:", err);
                setWordOfDay({
                    id: 0,
                    spanishText: "Habla bien",
                    mazahuaText: "Ki jñaa kjo"
                });
                setLoading(false);
            });
    }, []);

    return (
        <div className="min-h-screen">
            <NavbarHome />
            
            <main>
                <HeroHome wordOfDay={wordOfDay} />
                <MarqueeBanner />
                <LearnSection />
                <CulturalContentSection />
                <MultimodalSection />
            </main>
            
            <FooterHome />
        </div>
    );
};

export default Home;