// client/src/components/NavbarHome.jsx
import React, { useState, useEffect, useCallback } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import Roles from '../utils/roles';

const NavbarHome = () => {
    const navigate = useNavigate();
    const { user, logout } = useAuth();
    const [isHidden, setIsHidden] = useState(false);
    const [lastScrollY, setLastScrollY] = useState(0);

    const handleScroll = useCallback(() => {
        const currentScrollY = window.scrollY;
        
        if (currentScrollY > lastScrollY && currentScrollY > 100) {
            setIsHidden(true);
        } else {
            setIsHidden(false);
        }
        
        setLastScrollY(currentScrollY);
    }, [lastScrollY]);

    useEffect(() => {
        window.addEventListener('scroll', handleScroll, { passive: true });
        return () => window.removeEventListener('scroll', handleScroll);
    }, [handleScroll]);

    const handleLogout = () => {
        logout();
        navigate('/');
    };

    const getInitial = () => {
        if (!user) return '?';
        const name = user.name || user.username || '';
        return name.charAt(0).toUpperCase();
    };

    const getRouteAuthenticated = () => {
        switch (user?.userType) {
            case 'ADMIN': return '/admin/dashboard';
            case 'TEACHER': return '/maestro/dashboard';
            case 'STUDENT': return '/estudiante/dashboard';
            case 'VISITOR': return '/visitante/dashboard';
            default: return '/';
        }
    };

    const getRoleBadge = () => {
        if (!user) return null;
        const roleMap = {
            [Roles.TEACHER]: { label: 'Maestro', color: 'bg-green-100 text-green-700' },
            [Roles.STUDENT]: { label: 'Alumno', color: 'bg-blue-100 text-blue-700' },
            [Roles.VISITOR]: { label: 'Visitante', color: 'bg-purple-100 text-purple-700' },
            [Roles.ADMIN]: { label: 'Admin', color: 'bg-red-100 text-red-700' }
        };
        return roleMap[user.userType] || { label: user.userType, color: 'bg-gray-100 text-gray-700' };
    };

    return (
        <header 
            className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
                isHidden ? '-translate-y-full opacity-0' : 'translate-y-0 opacity-100'
            } bg-white/95 dark:bg-surface-dark/95 backdrop-blur-md shadow-sm border-b border-gray-200 dark:border-white/10`}
        >
            <div className="mx-auto flex h-16 max-w-7xl items-center justify-between px-4 sm:px-6 lg:px-8">
                {/* Logo + Nav */}
                <div className="flex items-center gap-8">
                    <Link to="/" className="flex items-center gap-2">
                        <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-primary/20 text-primary-dark">
                            <span className="material-symbols-outlined">school</span>
                        </div>
                        <h1 className="text-xl font-bold tracking-tight text-text-main-light dark:text-text-main-dark">
                            NTS'I FÍYO
                        </h1>
                    </Link>

                    <nav className="hidden md:flex items-center gap-6">
                        <Link
                            to="/nosotros"
                            className="text-sm font-semibold text-text-sub-light hover:text-primary transition-colors"
                        >
                            Nosotros
                        </Link>
                        <Link
                            to="/#learn"
                            className="text-sm font-semibold text-text-sub-light hover:text-primary transition-colors"
                        >
                            Aprende
                        </Link>
                        <Link
                            to="/#culture"
                            className="text-sm font-semibold text-text-sub-light hover:text-primary transition-colors"
                        >
                            Cultura
                        </Link>
                    </nav>
                </div>

                {/* Acciones de Usuario */}
                <div className="flex items-center gap-3">
                    {user ? (
                        <>
                            {getRoleBadge() && (
                                <span className={`hidden sm:inline-flex items-center px-2.5 py-1 text-xs font-semibold rounded-full ${getRoleBadge().color}`}>
                                    {getRoleBadge().label}
                                </span>
                            )}
                            <Link
                                to={getRouteAuthenticated()}
                                className="flex items-center gap-2 px-3 py-1.5 rounded-lg hover:bg-gray-100 dark:hover:bg-white/5 transition-colors"
                            >
                                <div className="w-8 h-8 rounded-full bg-primary flex items-center justify-center text-white font-bold text-sm">
                                    {getInitial()}
                                </div>
                                <span className="hidden sm:block text-sm font-medium text-text-main-light">
                                    {user.firstname}
                                </span>
                            </Link>
                            <button
                                onClick={handleLogout}
                                className="flex items-center justify-center h-9 px-3 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                            >
                                <span className="material-symbols-outlined text-lg">logout</span>
                            </button>
                        </>
                    ) : (
                        <>
                            <Link
                                to="/auth"
                                state={{ mode: 'login' }}
                                className="hidden sm:flex items-center justify-center h-9 px-4 text-sm font-medium text-text-main-light hover:bg-gray-100 rounded-lg transition-colors"
                            >
                                Iniciar Sesión
                            </Link>
                            <Link
                                to="/auth"
                                state={{ mode: 'register' }}
                                className="flex items-center justify-center h-9 px-4 bg-primary text-white font-bold text-sm rounded-lg hover:bg-primary-dark transition-colors shadow-sm"
                            >
                                Registrarse
                            </Link>
                        </>
                    )}
                </div>
            </div>
        </header>
    );
};

export default NavbarHome;