// client/src/components/HeroHome.jsx
import React, { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import '../styles/HomeStyles.css';

const LANDING_IMAGES = [
    '/assets/landing/image1.webp',
    '/assets/landing/image2.webp',
    '/assets/landing/image3.webp',
    '/assets/landing/image4.webp',
    '/assets/landing/image5.webp',
    '/assets/landing/image6.webp',
    '/assets/landing/image7.webp',
    '/assets/landing/image8.webp',
];

const HeroHome = ({ wordOfDay }) => {
    const [currentSlide, setCurrentSlide] = useState(0);
    const [parallaxOffset, setParallaxOffset] = useState(0);

    const handleScroll = useCallback(() => {
        const scrollY = window.scrollY;
        setParallaxOffset(scrollY * 0.3);
    }, []);

    useEffect(() => {
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, [handleScroll]);

    useEffect(() => {
        const interval = setInterval(() => {
            setCurrentSlide((prev) => (prev + 1) % LANDING_IMAGES.length);
        }, 3000);
        return () => clearInterval(interval);
    }, []);

    return (
        <section className="hero-carousel relative h-screen min-h-[600px] lg:min-h-[700px] overflow-hidden">
            {/* Imágenes del Carrusel */}
            {LANDING_IMAGES.map((image, index) => (
                <div
                    key={index}
                    className={`hero-slide ${index === currentSlide ? 'active' : ''}`}
                >
                    <div
                        className="absolute inset-0 bg-cover bg-center"
                        style={{
                            backgroundImage: `url('${image}')`,
                            transform: `scale(${index === currentSlide ? 1.1 : 1}) translateY(${parallaxOffset}px)`,
                        }}
                    />
                    <div className="absolute inset-0 bg-gradient-to-b from-black/40 via-black/20 to-black/60" />
                </div>
            ))}

            {/* Overlay de contenido */}
            <div className="hero-overlay relative z-10 flex flex-col items-center justify-center h-full px-4 text-center opacity-0 transition-opacity duration-1000">
                <div className="max-w-4xl mx-auto">
                    {/* Badge */}
                    <div className="inline-flex items-center gap-2 px-4 py-2 bg-white/20 backdrop-blur-md rounded-full text-white text-sm font-medium mb-6 animate-float">
                        <span className="w-2 h-2 bg-green-400 rounded-full pulse-dot" />
                        Aprende el Jñatrjo de tus ancestors
                    </div>

                    {/* Título Principal */}
                    <h1 className="text-5xl md:text-6xl lg:text-7xl font-black text-white leading-tight mb-6 drop-shadow-lg">
                        Revitaliza tus{' '}
                        <span className="text-transparent bg-clip-text bg-gradient-to-r from-orange-400 to-yellow-400">
                            Raíces
                        </span>
                        <br />
                        <span className="text-3xl md:text-4xl lg:text-5xl">Aprende Mazahua HOY</span>
                    </h1>

                    {/* Subtítulo */}
                    <p className="text-lg md:text-xl text-white/90 max-w-2xl mx-auto mb-8 leading-relaxed drop-shadow-md">
                        Conéctate con la tradición a través de una experiencia de aprendizaje moderna.
                        El Jñatrjo vive en ti.
                    </p>

                    {/* Botones */}
                    <div className="flex flex-col sm:flex-row gap-4 justify-center">
                        <Link
                            to="/auth"
                            state={{ mode: 'register' }}
                            className="btn-primary bg-primary hover:bg-primary-dark px-8 py-4 text-lg shadow-xl btn-glow"
                        >
                            <span className="material-symbols-outlined">school</span>
                            Comienza a aprender ahora
                        </Link>
                        <Link
                            to="/nosotros"
                            className="px-8 py-4 bg-white/20 backdrop-blur-md text-white font-bold text-lg rounded-xl border-2 border-white/30 hover:bg-white/30 transition-all"
                        >
                            Conócenos
                        </Link>
                    </div>
                </div>

                {/* Tarjeta de Palabra del Día */}
                <div className="mt-12 max-w-md mx-auto">
                    <div className="bg-white/95 dark:bg-surface-dark/95 backdrop-blur p-6 rounded-2xl shadow-2xl border border-white/20">
                        <div className="flex items-center gap-4">
                            <div className="h-12 w-12 rounded-full bg-primary/20 flex items-center justify-center shrink-0 text-primary-dark">
                                <span className="material-symbols-outlined">translate</span>
                            </div>
                            <div className="text-left">
                                <p className="text-sm font-bold text-gray-500 uppercase tracking-wide">
                                    Palabra del día
                                </p>
                                {wordOfDay ? (
                                    <>
                                        <p className="text-xl font-medium text-primary-dark">
                                            "{wordOfDay.mazahuaText}"
                                        </p>
                                        <p className="text-sm text-gray-600">
                                            Significa "{wordOfDay.spanishText}"
                                        </p>
                                    </>
                                ) : (
                                    <div className="flex items-center gap-2">
                                        <div className="animate-spin rounded-full h-4 w-4 border-2 border-primary border-t-transparent" />
                                        <span className="text-sm text-gray-500">Cargando...</span>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Indicadores de Slide */}
            <div className="absolute bottom-24 left-1/2 -translate-x-1/2 flex gap-2 z-20">
                {LANDING_IMAGES.map((_, index) => (
                    <button
                        key={index}
                        onClick={() => setCurrentSlide(index)}
                        className={`w-2 h-2 rounded-full transition-all duration-300 ${
                            index === currentSlide
                                ? 'w-8 bg-primary'
                                : 'bg-white/50 hover:bg-white/80'
                        }`}
                        aria-label={`Ver imagen ${index + 1}`}
                    />
                ))}
            </div>

            {/* Flecha hacia abajo */}
            <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-20 animate-bounce">
                <span className="material-symbols-outlined text-white/70 text-3xl">
                    keyboard_arrow_down
                </span>
            </div>
        </section>
    );
};

export default HeroHome;