import React, { useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';

const CULTURAL_ITEMS = [
    {
        icon: 'auto_stories',
        title: 'Historias',
        description: 'Historias tradicionales y leyendas de la cultura mazahua',
        color: '#7C3AED',
        gradient: 'from-violet-500 to-purple-600',
    },
    {
        icon: 'menu_book',
        title: 'Anécdotas',
        description: 'Relatos y experiencias de la comunidad',
        color: '#059669',
        gradient: 'from-emerald-500 to-green-600',
    },
    {
        icon: 'music_note',
        title: 'Canciones',
        description: 'Canciones tradicionales en Jñatrjo',
        color: '#DB2777',
        gradient: 'from-pink-500 to-rose-600',
    },
    {
        icon: 'edit_note',
        title: 'Poemas',
        description: 'Poesía y literatura en lengua mazahua',
        color: '#F59E0B',
        gradient: 'from-amber500 to-yellow-600',
    },
];

const CulturalContentSection = () => {
    const sectionRef = useRef(null);

    useEffect(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add('visible');
                    }
                });
            },
            { threshold: 0.1, rootMargin: '0px 0px -50px 0px' }
        );

        const elements = sectionRef.current?.querySelectorAll('.scroll-trigger');
        elements?.forEach((el) => observer.observe(el));

        return () => observer.disconnect();
    }, []);

    return (
        <section
            id="culture"
            className="section-padding bg-gradient-to-b from-white/90 to-primary/5"
            ref={sectionRef}
        >
            <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
                {/* Header */}
                <div className="scroll-trigger text-center mb-12">
                    <span className="inline-block px-4 py-1 bg-primary/10 text-primary-dark text-sm font-bold rounded-full mb-4">
                        CONTENIDO CULTURAL
                    </span>
                    <h2 className="text-3xl md:text-4xl font-black text-text-main-light dark:text-white">
                        Rica Herencia Cultural
                    </h2>
                    <p className="mt-4 text-lg text-text-sub-light dark:text-text-sub-dark max-w-2xl mx-auto">
                        Sumérgete en la riqueza cultural de nuestro pueblo.
                        Historias, canciones, poemas y más en la lengua originaria.
                    </p>
                </div>

                {/* Grid de contenido cultural */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 stagger-children">
                    {CULTURAL_ITEMS.map((item, index) => (
                        <Link
                            key={index}
                            to="/estudiante/contenido"
                            className="scroll-trigger group relative overflow-hidden rounded-2xl bg-white dark:bg-surface-dark shadow-lg hover:shadow-2xl transition-all hover-card"
                        >
                            {/* Gradient overlay */}
                            <div
                                className={`absolute inset-0 bg-gradient-to-br ${item.gradient} opacity-0 group-hover:opacity-20 transition-opacity duration-300`}
                            />
                            
                            <div className="relative p-6">
                                <div
                                    className="h-14 w-14 rounded-xl flex items-center justify-center mb-4 transition-transform group-hover:scale-110 group-hover:rotate-6"
                                    style={{ backgroundColor: item.color + '20', color: item.color }}
                                >
                                    <span className="material-symbols-outlined text-3xl">
                                        {item.icon}
                                    </span>
                                </div>
                                <h3 className="font-bold text-xl mb-2 text-text-main-light dark:text-white group-hover:text-primary-dark transition-colors">
                                    {item.title}
                                </h3>
                                <p className="text-sm text-text-sub-light dark:text-text-sub-dark mb-4">
                                    {item.description}
                                </p>
                                <div 
                                    className="inline-flex items-center text-sm font-semibold"
                                    style={{ color: item.color }}
                                >
                                    <span>Ver más</span>
                                    <span className="material-symbols-outlined text-lg ml-1 transition-transform group-hover:translate-x-1">
                                        arrow_forward
                                    </span>
                                </div>
                            </div>
                        </Link>
                    ))}
                </div>
            </div>
        </section>
    );
};

export default CulturalContentSection;