import React, { useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';

const LEARN_ITEMS = [
    {
        icon: 'groups',
        title: 'Nosotros',
        description: 'Conoce al equipo detrás del proyecto',
        link: '/nosotros',
        color: '#6C63FF',
    },
    {
        icon: 'sports_esports',
        title: 'Juegos',
        description: '8 juegos interactivos para aprender',
        link: '/#games',
        color: '#E65100',
    },
    {
        icon: 'translate',
        title: 'Palabras',
        description: 'Categorías de vocabulario',
        link: '/#categories',
        color: '#10B981',
    },
    {
        icon: 'chat',
        title: 'Frases',
        description: 'Aprende frases comunes',
        link: '/#phrases',
        color: '#F59E0B',
    },
];

const LearnSection = () => {
    const sectionRef = useRef(null);

    useEffect(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add('visible');
                    }
                });
            },
            { threshold: 0.1, rootMargin: '0px 0px -50px 0px' }
        );

        const elements = sectionRef.current?.querySelectorAll('.reveal');
        elements?.forEach((el) => observer.observe(el));

        return () => observer.disconnect();
    }, []);

    return (
        <section
            id="learn"
            className="section-padding bg-white/90 dark:bg-surface-dark/90"
            ref={sectionRef}
        >
            <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
                {/* Header */}
                <div className="reveal text-center mb-12">
                    <span className="inline-block px-4 py-1 bg-primary/10 text-primary-dark text-sm font-bold rounded-full mb-4">
                        LO QUE PUEDES APRENDER
                    </span>
                    <h2 className="text-3xl md:text-4xl font-black text-text-main-light dark:text-white">
                        Explora el Mundo del Jñatrjo
                    </h2>
                    <p className="mt-4 text-lg text-text-sub-light dark:text-text-sub-dark max-w-2xl mx-auto">
                        Desde juegos interactivos hasta contenido cultural auténtico.
                        Todo lo que necesitas para aprender y preservar la lengua mazahua.
                    </p>
                </div>

                {/* Grid de funcionalidades */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {LEARN_ITEMS.map((item, index) => (
                        <Link
                            key={index}
                            to={item.link}
                            className="reveal group p-6 rounded-2xl bg-white dark:bg-surface-dark border-2 border-transparent hover:border-primary/30 transition-all hover-card"
                        >
                            <div
                                className="h-12 w-12 rounded-xl flex items-center justify-center mb-4 transition-transform group-hover:scale-110"
                                style={{ backgroundColor: item.color + '20', color: item.color }}
                            >
                                <span className="material-symbols-outlined text-2xl">
                                    {item.icon}
                                </span>
                            </div>
                            <h3 className="font-bold text-lg mb-2 text-text-main-light dark:text-white group-hover:text-primary-dark transition-colors">
                                {item.title}
                            </h3>
                            <p className="text-sm text-text-sub-light dark:text-text-sub-dark">
                                {item.description}
                            </p>
                            <div className="mt-4 flex items-center text-primary font-medium text-sm">
                                <span>Explorar</span>
                                <span className="material-symbols-outlined text-lg ml-1 transition-transform group-hover:translate-x-1">
                                    arrow_forward
                                </span>
                            </div>
                        </Link>
                    ))}
                </div>
            </div>
        </section>
    );
};

export default LearnSection;