import React, { useEffect, useRef } from 'react';

const MULTIMODAL_FEATURES = [
    {
        icon: 'image',
        title: 'Imágenes',
        description: 'Visual aprendizaje con imágenes authentique',
        color: '#E65100',
    },
    {
        icon: 'volume_up',
        title: 'Audios',
        description: 'Grabaciones de parlantes nativos',
        color: '#1E3A8A',
    },
    {
        icon: 'text_fields',
        title: 'Textos',
        description: 'Español y Mazahua lado a lado',
        color: '#10B981',
    },
    {
        icon: 'compare',
        title: 'Bilingual',
        description: 'Contenido en ambos idiomas',
        color: '#7C3AED',
    },
];

const MultimodalSection = () => {
    const sectionRef = useRef(null);

    useEffect(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add('visible');
                    }
                });
            },
            { threshold: 0.1, rootMargin: '0px 0px -50px 0px' }
        );

        const elements = sectionRef.current?.querySelectorAll('.reveal');
        elements?.forEach((el) => observer.observe(el));

        return () => observer.disconnect();
    }, []);

    return (
        <section
            id="multimodal"
            className="section-padding bg-primary-dark text-white"
            ref={sectionRef}
        >
            <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
                {/* Header */}
                <div className="reveal text-center mb-12">
                    <span className="inline-block px-4 py-1 bg-white/20 text-white text-sm font-bold rounded-full mb-4">
                        APRENDIZAJE MULTIMODAL
                    </span>
                    <h2 className="text-3xl md:text-4xl font-black">
                        Aprende de Forma Integrada
                    </h2>
                    <p className="mt-4 text-lg text-white/80 max-w-2xl mx-auto">
                        Nuestro sistema utiliza imágenes, audios y textos en ambos idiomas
                        para crear una experiencia de aprendizaje completa y auténtica.
                    </p>
                </div>

                {/* Grid de características */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 stagger-children">
                    {MULTIMODAL_FEATURES.map((feature, index) => (
                        <div
                            key={index}
                            className="reveal group p-6 rounded-2xl bg-white/10 backdrop-blur-sm border border-white/10 hover:border-white/30 transition-all"
                        >
                            <div
                                className="h-12 w-12 rounded-xl flex items-center justify-center mb-4 transition-transform group-hover:scale-110"
                                style={{ backgroundColor: feature.color + '30', color: feature.color }}
                            >
                                <span className="material-symbols-outlined text-2xl">
                                    {feature.icon}
                                </span>
                            </div>
                            <h3 className="font-bold text-lg mb-2 text-white">
                                {feature.title}
                            </h3>
                            <p className="text-sm text-white/70">
                                {feature.description}
                            </p>
                        </div>
                    ))}
                </div>

                {/* Demo visual */}
                <div className="reveal mt-16 p-8 bg-white/10 rounded-3xl border border-white/20">
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-center">
                        {/* Español */}
                        <div className="text-center p-4">
                            <span className="text-xs font-bold text-white/50 uppercase tracking-wider">
                                Español
                            </span>
                            <p className="text-xl font-medium text-white mt-2">
                                "Buenos días"
                            </p>
                        </div>

                        {/* Flecha center */}
                        <div className="flex justify-center">
                            <div className="h-10 w-10 rounded-full bg-primary flex items-center justify-center">
                                <span className="material-symbols-outlined text-white">
                                    arrow_forward
                                </span>
                            </div>
                        </div>

                        {/* Mazahua */}
                        <div className="text-center p-4">
                            <span className="text-xs font-bold text-orange-300 uppercase tracking-wider">
                                Jñatrjo
                            </span>
                            <p className="text-xl font-bold text-orange-400 mt-2">
                                "Kóyotik"
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default MultimodalSection;